    15→//go:build darwin
    16→
    17→package sandbox
    18→
    19→import (
    20→	"context"
    21→	"fmt"
    22→	"net"
    23→	"runtime"
    24→
    25→	"github.com/jingkaihe/matchlock/pkg/api"
    26→	"github.com/jingkaihe/matchlock/pkg/image"
    27→	matchlocksandbox "github.com/jingkaihe/matchlock/pkg/sandbox"
    28→)
    29→
    30→// darwinRuntime implements Runtime using Matchlock with Apple Virtualization.framework.
    31→type darwinRuntime struct {
    32→	kernelPath    string
    33→	initramfsPath string
    34→	rootfsPath    string
    35→}
    36→
    37→// NewRuntime creates a new Darwin runtime using Virtualization.framework via Matchlock.
    38→func NewRuntime() (Runtime, error) {
    39→	// Virtualization.framework is only available on Apple Silicon
    40→	if runtime.GOARCH != "arm64" {
    41→		return nil, fmt.Errorf("%w: darwin/amd64 not supported", ErrUnsupportedPlatform)
    42→	}
    43→
    44→	return &darwinRuntime{
    45→		kernelPath:    matchlocksandbox.DefaultKernelPath(),
    46→		initramfsPath: matchlocksandbox.DefaultInitramfsPath(),
    47→		rootfsPath:    "", // Must be set via config
    48→	}, nil
    49→}
    50→
    51→// Create creates a new VM using Virtualization.framework via Matchlock.
    52→func (r *darwinRuntime) Create(ctx context.Context, config *Config) (VM, error) {
    53→	if config == nil {
    54→		config = &Config{}
    55→	}
    56→
    57→	// Check for required system dependencies (e2fsprogs).
    58→	// Matchlock requires mke2fs, debugfs, and resize2fs for ext4 image manipulation.
    59→	if err := checkE2fsprogs(); err != nil {
    60→		return nil, err
    61→	}
    62→
    63→	// Ensure guest binaries are downloaded before creating the sandbox.
    64→	// Matchlock expects these in ~/.cache/matchlock/.
    65→	if err := ensureGuestBinaries(ctx); err != nil {
    66→		return nil, fmt.Errorf("ensure guest binaries: %w", err)
    67→	}
    68→
    69→	// Build Matchlock API config
    70→	apiConfig := &api.Config{
    71→		Resources: &api.Resources{
    72→			CPUs:       1,
    73→			MemoryMB:   512,
    74→			DiskSizeMB: 1024,
    75→		},
    76→	}
    77→
    78→	if config.Resources != nil {
    79→		if config.Resources.CPUs > 0 {
    80→			apiConfig.Resources.CPUs = config.Resources.CPUs
    81→		}
    82→		if config.Resources.MemoryMB > 0 {
    83→			apiConfig.Resources.MemoryMB = config.Resources.MemoryMB
    84→		}
    85→		if config.Resources.DiskMB > 0 {
    86→			apiConfig.Resources.DiskSizeMB = config.Resources.DiskMB
    87→		}
    88→	}
    89→
    90→	// Configure VFS for workspace mounting
    91→	if config.WorkspaceRoot != "" {
    92→		workspace := "/workspace"
    93→		if config.Policy != nil && config.Policy.Filesystem != nil &&
    94→			config.Policy.Filesystem.WorkspaceMountPoint != "" {
    95→			workspace = config.Policy.Filesystem.WorkspaceMountPoint
    96→		}
    97→
    98→		apiConfig.VFS = &api.VFSConfig{
    99→			Workspace: workspace,
   100→			Mounts: map[string]api.MountConfig{
   101→				workspace: {
   102→					Type:     "real_fs",
   103→					HostPath: config.WorkspaceRoot,
   104→				},
   105→			},
   106→		}
   107→	}
   108→
   109→	// Configure network policy
   110→	if config.Policy != nil && config.Policy.Network != nil {
   111→		apiConfig.Network = &api.NetworkConfig{
   112→			BlockPrivateIPs: true,
   113→		}
   114→		if !config.Policy.Network.BlockAllEgress {
   115→			apiConfig.Network.AllowedHosts = config.Policy.Network.AllowedHosts
   116→		}
   117→	}
   118→
   119→	// Resolve image reference to rootfs path
   120→	imageRef := config.Image
   121→	if imageRef == "" {
   122→		imageRef = DefaultImage
   123→	}
   124→
   125→	builder := image.NewBuilder(&image.BuildOptions{})
   126→	buildResult, err := builder.Build(ctx, imageRef)
   127→	if err != nil {
   128→		return nil, fmt.Errorf("build image %s: %w", imageRef, err)
   129→	}
   130→
   131→	// Create Matchlock sandbox
   132→	opts := &matchlocksandbox.Options{
   133→		KernelPath:    r.kernelPath,
   134→		InitramfsPath: r.initramfsPath,
   135→		RootfsPath:    buildResult.RootfsPath,
   136→	}
   137→
   138→	sb, err := matchlocksandbox.New(ctx, apiConfig, opts)
   139→	if err != nil {
   140→		return nil, fmt.Errorf("create matchlock sandbox: %w", err)
   141→	}
   142→
   143→	// Start the VM
   144→	if err := sb.Start(ctx); err != nil {
   145→		_ = sb.Close(ctx)
   146→		return nil, fmt.Errorf("start sandbox: %w", err)
   147→	}
   148→
   149→	return &darwinVM{
   150→		id:      sb.ID(),
   151→		state:   VMStateRunning,
   152→		config:  config,
   153→		sandbox: sb,
   154→	}, nil
   155→}
   156→
   157→// darwinVM represents a macOS VM managed by Matchlock.
   158→type darwinVM struct {
   159→	id      string
   160→	state   VMState
   161→	config  *Config
   162→	sandbox *matchlocksandbox.Sandbox
   163→}
   164→
   165→// ID returns the VM identifier.
   166→func (v *darwinVM) ID() string {
   167→	return v.id
   168→}
   169→
   170→// State returns the VM state.
   171→func (v *darwinVM) State() VMState {
   172→	return v.state
   173→}
   174→
   175→// AgentConn returns a connection to the guest agent.
   176→// On Darwin with Matchlock, we use the exec relay socket.
   177→func (v *darwinVM) AgentConn() (net.Conn, error) {
   178→	// Matchlock doesn't expose a direct vsock connection in its API.
   179→	// Instead, commands are executed via sandbox.Exec().
   180→	return nil, fmt.Errorf("darwin runtime uses Matchlock exec, not agent connection")
   181→}
   182→
   183→// Sandbox returns the underlying Matchlock sandbox for direct command execution.
   184→func (v *darwinVM) Sandbox() *matchlocksandbox.Sandbox {
   185→	return v.sandbox
   186→}
   187→
   188→// Exec executes a command in the VM using Matchlock's built-in mechanism.
   189→func (v *darwinVM) Exec(ctx context.Context, command string, opts *ExecOptions) (*ExecResult, error) {
   190→	matchlockOpts := &api.ExecOptions{}
   191→	if opts != nil {
   192→		matchlockOpts.WorkingDir = opts.WorkingDir
   193→		matchlockOpts.Env = opts.Env
   194→		matchlockOpts.User = opts.User
   195→		matchlockOpts.Stdin = opts.Stdin
   196→		matchlockOpts.Stdout = opts.Stdout
   197→		matchlockOpts.Stderr = opts.Stderr
   198→	}
   199→
   200→	result, err := v.sandbox.Exec(ctx, command, matchlockOpts)
   201→	if err != nil {
   202→		return nil, err
   203→	}
   204→
   205→	return &ExecResult{
   206→		ExitCode: result.ExitCode,
   207→		Stdout:   result.Stdout,
   208→		Stderr:   result.Stderr,
   209→	}, nil
   210→}
   211→
   212→// WriteFile writes a file to the VM's VFS.
   213→func (v *darwinVM) WriteFile(ctx context.Context, path string, content []byte, mode uint32) error {
   214→	return v.sandbox.WriteFile(ctx, path, content, mode)
   215→}
   216→
   217→// ReadFile reads a file from the VM's VFS.
   218→func (v *darwinVM) ReadFile(ctx context.Context, path string) ([]byte, error) {
   219→	return v.sandbox.ReadFile(ctx, path)
   220→}
   221→
   222→// Close stops and destroys the VM.
   223→func (v *darwinVM) Close() error {
   224→	v.state = VMStateStopped
   225→	return v.sandbox.Close(context.Background())
   226→}
   227→
   228→// Ensure darwinVM implements ExecutableVM
   229→var _ ExecutableVM = (*darwinVM)(nil)
   230→

