    15→// Package sandbox provides a secure execution environment for running
    16→// commands from extensions. Commands run inside an isolated virtual machine,
    17→// protecting the host system from malicious or buggy extension code.
    18→package sandbox
    19→
    20→import (
    21→	"bytes"
    22→	"context"
    23→	"errors"
    24→	"fmt"
    25→	"io"
    26→	"log/slog"
    27→	"net"
    28→	"strings"
    29→	"sync"
    30→	"sync/atomic"
    31→	"syscall"
    32→	"time"
    33→
    34→	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
    35→	"github.com/unstablebuild/rune-go-sdk/sandbox/policy"
    36→	"github.com/unstablebuild/rune-go-sdk/sandbox/sandboxrpc"
    37→	"google.golang.org/grpc"
    38→	"google.golang.org/grpc/credentials/insecure"
    39→)
    40→
    41→const agentConnectTimeout = 30 * time.Second
    42→
    43→// Ensure Executor implements workspaceapi.Executor
    44→var _ workspaceapi.Executor = (*Executor)(nil)
    45→
    46→// Executor implements workspaceapi.Executor by running commands inside a
    47→// sandboxed virtual machine.
    48→type Executor struct {
    49→	config  Config
    50→	runtime Runtime
    51→	vm      VM
    52→	agent   *sandboxrpc.Client
    53→	conn    *grpc.ClientConn
    54→	log     *slog.Logger
    55→
    56→	// For ExecutableVM mode
    57→	execVM     ExecutableVM
    58→	pidCounter atomic.Int64
    59→	processes  sync.Map // map[workspaceapi.Pid]context.CancelFunc
    60→
    61→	mu     sync.RWMutex
    62→	closed bool
    63→}
    64→
    65→// Option is a functional option for configuring an Executor.
    66→type Option func(*Executor)
    67→
    68→// WithRuntime sets a custom runtime for the executor.
    69→// This is primarily used for testing.
    70→func WithRuntime(r Runtime) Option {
    71→	return func(e *Executor) {
    72→		e.runtime = r
    73→	}
    74→}
    75→
    76→// WithLogger sets a custom logger for the executor.
    77→func WithLogger(log *slog.Logger) Option {
    78→	return func(e *Executor) {
    79→		e.log = log
    80→	}
    81→}
    82→
    83→// New creates a new sandbox executor. The VM is started immediately and
    84→// will be ready to accept commands upon return. The caller is responsible
    85→// for calling Close() when the executor is no longer needed.
    86→func New(ctx context.Context, config Config, opts ...Option) (*Executor, error) {
    87→	e := &Executor{
    88→		config: config,
    89→		log:    slog.Default().With("struct", "sandbox.Executor"),
    90→	}
    91→
    92→	for _, opt := range opts {
    93→		opt(e)
    94→	}
    95→
    96→	// Use default runtime if not provided
    97→	if e.runtime == nil {
    98→		runtime, err := NewRuntime()
    99→		if err != nil {
   100→			return nil, fmt.Errorf("create runtime: %w", err)
   101→		}
   102→		e.runtime = runtime
   103→	}
   104→
   105→	// Create the VM
   106→	vm, err := e.runtime.Create(ctx, &config)
   107→	if err != nil {
   108→		return nil, fmt.Errorf("create vm: %w", err)
   109→	}
   110→	e.vm = vm
   111→
   112→	// Check if VM supports direct execution (e.g., Matchlock VMs)
   113→	if execVM, ok := vm.(ExecutableVM); ok {
   114→		e.execVM = execVM
   115→		e.log.Info("sandbox executor ready (direct exec)", "vm_id", vm.ID())
   116→		return e, nil
   117→	}
   118→
   119→	// Fall back to gRPC agent connection
   120→	if err := e.connectAgent(ctx); err != nil {
   121→		_ = vm.Close()
   122→		return nil, fmt.Errorf("connect agent: %w", err)
   123→	}
   124→
   125→	e.log.Info("sandbox executor ready (agent)", "vm_id", vm.ID())
   126→	return e, nil
   127→}
   128→
   129→func (e *Executor) connectAgent(ctx context.Context) error {
   130→	timeoutCtx, cancel := context.WithTimeout(ctx, agentConnectTimeout)
   131→	defer cancel()
   132→
   133→	// Get connection to the agent
   134→	agentConn, err := e.vm.AgentConn()
   135→	if err != nil {
   136→		return fmt.Errorf("get agent connection: %w", err)
   137→	}
   138→
   139→	// Create gRPC connection over the net.Conn
   140→	grpcConn, err := grpc.NewClient(
   141→		"passthrough:///sandbox",
   142→		grpc.WithTransportCredentials(insecure.NewCredentials()),
   143→		grpc.WithContextDialer(func(_ context.Context, _ string) (net.Conn, error) {
   144→			return agentConn, nil
   145→		}),
   146→	)
   147→	if err != nil {
   148→		_ = agentConn.Close()
   149→		return fmt.Errorf("create grpc connection: %w", err)
   150→	}
   151→	e.conn = grpcConn
   152→
   153→	// Create the agent client with a background context (lives until Close)
   154→	e.agent = sandboxrpc.NewClient(context.Background(), grpcConn)
   155→
   156→	// Ping the agent to verify it's ready
   157→	if err := e.agent.Ping(timeoutCtx); err != nil {
   158→		_ = grpcConn.Close()
   159→		_ = agentConn.Close()
   160→		return fmt.Errorf("ping agent: %w", err)
   161→	}
   162→
   163→	return nil
   164→}
   165→
   166→// Start starts a command in the sandbox and returns its PID.
   167→// This method implements workspaceapi.Executor.
   168→func (e *Executor) Start(
   169→	ctx context.Context, cmd workspaceapi.Cmd,
   170→) (workspaceapi.Pid, error) {
   171→	e.mu.RLock()
   172→	defer e.mu.RUnlock()
   173→
   174→	if e.closed {
   175→		return 0, ErrClosed
   176→	}
   177→
   178→	if cmd.Path == "" {
   179→		return 0, ErrInvalidCommand
   180→	}
   181→
   182→	// Scrub environment variables according to policy
   183→	cmd.Env = e.scrubEnvironment(cmd.Env)
   184→
   185→	// Use direct exec if available
   186→	if e.execVM != nil {
   187→		return e.startWithExec(ctx, cmd)
   188→	}
   189→
   190→	// Fall back to agent
   191→	return e.agent.StartCommand(ctx, cmd)
   192→}
   193→
   194→// scrubEnvironment filters environment variables according to the configured policy.
   195→func (e *Executor) scrubEnvironment(env []string) []string {
   196→	var envPolicy *policy.EnvironmentPolicy
   197→	if e.config.Policy != nil {
   198→		envPolicy = e.config.Policy.Environment
   199→	}
   200→	if envPolicy == nil {
   201→		// Use default policy if none configured
   202→		envPolicy = policy.DefaultEnvironmentPolicy()
   203→	}
   204→	return envPolicy.ScrubEnvironment(env)
   205→}
   206→
   207→// startWithExec uses the VM's direct Exec method.
   208→func (e *Executor) startWithExec(ctx context.Context, cmd workspaceapi.Cmd) (workspaceapi.Pid, error) {
   209→	// Build command string
   210→	command := cmd.Path
   211→	if len(cmd.Args) > 0 {
   212→		command = command + " " + strings.Join(cmd.Args, " ")
   213→	}
   214→
   215→	// Create exec options
   216→	opts := &ExecOptions{
   217→		WorkingDir: cmd.Dir,
   218→		Env:        make(map[string]string),
   219→	}
   220→
   221→	// Parse environment variables
   222→	for _, env := range cmd.Env {
   223→		parts := strings.SplitN(env, "=", 2)
   224→		if len(parts) == 2 {
   225→			opts.Env[parts[0]] = parts[1]
   226→		}
   227→	}
   228→
   229→	// Set up I/O
   230→	opts.Stdin = cmd.Stdin
   231→	opts.Stdout = cmd.Stdout
   232→	opts.Stderr = cmd.Stderr
   233→
   234→	// Generate PID
   235→	pid := workspaceapi.Pid(e.pidCounter.Add(1))
   236→
   237→	// Create cancellable context for this process
   238→	procCtx, cancel := context.WithCancel(ctx)
   239→	e.processes.Store(pid, cancel)
   240→
   241→	// Run command in background
   242→	go func() {
   243→		defer e.processes.Delete(pid)
   244→		defer cancel()
   245→
   246→		var stdoutBuf, stderrBuf bytes.Buffer
   247→		execOpts := &ExecOptions{
   248→			WorkingDir: opts.WorkingDir,
   249→			Env:        opts.Env,
   250→		}
   251→
   252→		// If streaming I/O is provided, pass it through
   253→		if opts.Stdout != nil {
   254→			execOpts.Stdout = opts.Stdout
   255→		} else {
   256→			execOpts.Stdout = &stdoutBuf
   257→		}
   258→		if opts.Stderr != nil {
   259→			execOpts.Stderr = opts.Stderr
   260→		} else {
   261→			execOpts.Stderr = &stderrBuf
   262→		}
   263→		if opts.Stdin != nil {
   264→			execOpts.Stdin = opts.Stdin
   265→		}
   266→
   267→		result, err := e.execVM.Exec(procCtx, command, execOpts)
   268→
   269→		// Notify watcher
   270→		if cmd.Watcher != nil && cmd.Watcher.WatchProcess() != nil {
   271→			var watchErr error
   272→			if err != nil {
   273→				watchErr = err
   274→			} else if result != nil && result.ExitCode != 0 {
   275→				watchErr = fmt.Errorf("exit status %d", result.ExitCode)
   276→			}
   277→
   278→			select {
   279→			case cmd.Watcher.WatchProcess() <- watchErr:
   280→			case <-time.After(2 * time.Minute):
   281→				e.log.Warn("watcher not ready, dropping result")
   282→			}
   283→		}
   284→
   285→		// Close output streams if they implement io.Closer
   286→		if closer, ok := cmd.Stdout.(io.Closer); ok {
   287→			_ = closer.Close()
   288→		}
   289→		if closer, ok := cmd.Stderr.(io.Closer); ok {
   290→			_ = closer.Close()
   291→		}
   292→	}()
   293→
   294→	return pid, nil
   295→}
   296→
   297→// Signal sends a signal to a process running in the sandbox.
   298→// This method implements workspaceapi.Executor.
   299→func (e *Executor) Signal(pid workspaceapi.Pid, sig syscall.Signal) error {
   300→	e.mu.RLock()
   301→	defer e.mu.RUnlock()
   302→
   303→	if e.closed {
   304→		return ErrClosed
   305→	}
   306→
   307→	if pid <= 0 {
   308→		return ErrProcessNotFound
   309→	}
   310→
   311→	// Use direct cancellation for ExecutableVM
   312→	if e.execVM != nil {
   313→		v, ok := e.processes.Load(pid)
   314→		if !ok {
   315→			return ErrProcessNotFound
   316→		}
   317→		cancel := v.(context.CancelFunc)
   318→		// For SIGTERM/SIGKILL, cancel the context
   319→		if sig == syscall.SIGTERM || sig == syscall.SIGKILL {
   320→			cancel()
   321→		}
   322→		return nil
   323→	}
   324→
   325→	// Fall back to agent
   326→	return e.agent.Signal(pid, sig)
   327→}
   328→
   329→// Close stops the sandbox and releases all resources.
   330→// This method implements io.Closer.
   331→func (e *Executor) Close() error {
   332→	e.mu.Lock()
   333→	defer e.mu.Unlock()
   334→
   335→	if e.closed {
   336→		return nil
   337→	}
   338→	e.closed = true
   339→
   340→	var errs []error
   341→
   342→	// Cancel all running processes
   343→	e.processes.Range(func(_, value any) bool {
   344→		cancel := value.(context.CancelFunc)
   345→		cancel()
   346→		return true
   347→	})
   348→
   349→	if e.agent != nil {
   350→		if err := e.agent.Close(); err != nil {
   351→			errs = append(errs, fmt.Errorf("close agent: %w", err))
   352→		}
   353→	}
   354→
   355→	if e.conn != nil {
   356→		if err := e.conn.Close(); err != nil {
   357→			errs = append(errs, fmt.Errorf("close grpc conn: %w", err))
   358→		}
   359→	}
   360→
   361→	if e.vm != nil {
   362→		if err := e.vm.Close(); err != nil {
   363→			errs = append(errs, fmt.Errorf("close vm: %w", err))
   364→		}
   365→	}
   366→
   367→	e.log.Info("sandbox executor closed", "vm_id", e.vm.ID())
   368→	return errors.Join(errs...)
   369→}
   370→
   371→// VM returns the underlying VM. This is primarily for testing.
   372→func (e *Executor) VM() VM {
   373→	return e.vm
   374→}
   375→
   376→// Config returns the executor's configuration.
   377→func (e *Executor) Config() Config {
   378→	return e.config
   379→}
