     5→package sandbox;
     6→
     7→// AgentService is the gRPC service that runs inside the guest VM.
     8→// The host connects to this service via vsock to execute commands.
     9→service Agent {
    10→    // StartCommand starts a command and streams stdin/stdout/stderr.
    11→    rpc StartCommand(stream CommandMessage) returns (stream CommandMessage);
    12→
    13→    // Signal sends a signal to a running process.
    14→    rpc Signal(SignalRequest) returns (SignalResponse);
    15→
    16→    // Ping checks if the agent is alive.
    17→    rpc Ping(PingRequest) returns (PingResponse);
    18→}
    19→
    20→// CommandMessage is the bidirectional streaming message for command I/O.
    21→message CommandMessage {
    22→    // Type indicates the message type.
    23→    Type type = 1;
    24→
    25→    // StartRequest is set when type is TYPE_START.
    26→    StartRequest start = 2;
    27→
    28→    // Started is set when type is TYPE_STARTED.
    29→    StartedResponse started = 3;
    30→
    31→    // IO is set when type is TYPE_IO.
    32→    IOData io = 4;
    33→
    34→    // Done is set when type is TYPE_DONE.
    35→    DoneResponse done = 5;
    36→
    37→    // Error is set when type is TYPE_ERROR.
    38→    string error = 6;
    39→
    40→    enum Type {
    41→        TYPE_START = 0;
    42→        TYPE_STARTED = 1;
    43→        TYPE_IO = 2;
    44→        TYPE_DONE = 3;
    45→        TYPE_ERROR = 4;
    46→    }
    47→}
    48→
    49→// StartRequest contains the command to start.
    50→message StartRequest {
    51→    // Path is the path to the executable.
    52→    string path = 1;
    53→
    54→    // Args are the command arguments (not including path).
    55→    repeated string args = 2;
    56→
    57→    // Dir is the working directory. If empty, uses the workspace root.
    58→    string dir = 3;
    59→
    60→    // Env contains environment variables in KEY=value format.
    61→    repeated string env = 4;
    62→
    63→    // HasStdin indicates whether stdin will be provided.
    64→    bool has_stdin = 5;
    65→
    66→    // HasStdout indicates whether stdout should be captured.
    67→    bool has_stdout = 6;
    68→
    69→    // HasStderr indicates whether stderr should be captured.
    70→    bool has_stderr = 7;
    71→}
    72→
    73→// StartedResponse indicates a command has started.
    74→message StartedResponse {
    75→    // Pid is the process ID of the started command.
    76→    int64 pid = 1;
    77→}
    78→
    79→// IOData contains stdin/stdout/stderr data.
    80→message IOData {
    81→    // Type indicates which stream this data is for.
    82→    IOType type = 1;
    83→
    84→    // Data is the actual bytes.
    85→    bytes data = 2;
    86→
    87→    enum IOType {
    88→        IO_STDIN = 0;
    89→        IO_STDOUT = 1;
    90→        IO_STDERR = 2;
    91→    }
    92→}
    93→
    94→// DoneResponse indicates a command has completed.
    95→message DoneResponse {
    96→    // ExitCode is the exit code of the process.
    97→    int32 exit_code = 1;
    98→
    99→    // ExitError contains an error message if the process failed.
   100→    string exit_error = 2;
   101→}
   102→
   103→// SignalRequest sends a signal to a process.
   104→message SignalRequest {
   105→    // Pid is the process ID to signal.
   106→    int64 pid = 1;
   107→
   108→    // Signal is the signal number to send.
   109→    int32 signal = 2;
   110→}
   111→
   112→// SignalResponse is the response to a signal request.
   113→message SignalResponse {
   114→}
   115→
   116→// PingRequest is a health check request.
   117→message PingRequest {
   118→}
   119→
   120→// PingResponse is a health check response.
   121→message PingResponse {
   122→    // Version is the agent version.
   123→    string version = 1;
   124→}
