    15→package sandboxrpc
    16→
    17→import (
    18→	"context"
    19→	"fmt"
    20→	"io"
    21→	"log/slog"
    22→	"syscall"
    23→	"time"
    24→
    25→	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
    26→	"google.golang.org/grpc"
    27→)
    28→
    29→const defaultTimeout = 5 * time.Second
    30→
    31→// Client connects to the guest agent running inside the sandbox VM.
    32→type Client struct {
    33→	agent AgentClient
    34→	ctx   context.Context
    35→	log   *slog.Logger
    36→}
    37→
    38→// NewClient creates a new client connected to the agent via the given gRPC
    39→// connection.
    40→func NewClient(ctx context.Context, cc grpc.ClientConnInterface) *Client {
    41→	return &Client{
    42→		agent: NewAgentClient(cc),
    43→		ctx:   ctx,
    44→		log:   slog.Default().With("struct", "sandboxrpc.Client"),
    45→	}
    46→}
    47→
    48→// StartCommand starts a command in the sandbox and returns its PID.
    49→// The cmd's Stdin, Stdout, and Stderr are streamed to/from the sandbox.
    50→func (c *Client) StartCommand(
    51→	ctx context.Context, cmd workspaceapi.Cmd,
    52→) (workspaceapi.Pid, error) {
    53→	stream, err := c.agent.StartCommand(ctx)
    54→	if err != nil {
    55→		return 0, fmt.Errorf("start command stream: %w", err)
    56→	}
    57→
    58→	streamer := newClientStreamer(ctx, cmd, stream, c.log)
    59→	return streamer.start()
    60→}
    61→
    62→// Signal sends a signal to a process running in the sandbox.
    63→func (c *Client) Signal(pid workspaceapi.Pid, sig syscall.Signal) error {
    64→	ctx, cancel := context.WithTimeout(c.ctx, defaultTimeout)
    65→	defer cancel()
    66→
    67→	_, err := c.agent.Signal(ctx, &SignalRequest{
    68→		Pid:    int64(pid),
    69→		Signal: int32(sig),
    70→	})
    71→	return err
    72→}
    73→
    74→// Ping checks if the agent is alive.
    75→func (c *Client) Ping(ctx context.Context) error {
    76→	ctx, cancel := context.WithTimeout(ctx, defaultTimeout)
    77→	defer cancel()
    78→
    79→	_, err := c.agent.Ping(ctx, &PingRequest{})
    80→	return err
    81→}
    82→
    83→// Close closes the client.
    84→func (c *Client) Close() error {
    85→	return nil
    86→}
    87→
    88→// clientStreamer handles bidirectional streaming for a command.
    89→type clientStreamer struct {
    90→	cmd    workspaceapi.Cmd
    91→	stream Agent_StartCommandClient
    92→	ctx    context.Context
    93→	quitCh chan struct{}
    94→	log    *slog.Logger
    95→}
    96→
    97→func newClientStreamer(
    98→	ctx context.Context,
    99→	cmd workspaceapi.Cmd,
   100→	stream Agent_StartCommandClient,
   101→	log *slog.Logger,
   102→) *clientStreamer {
   103→	return &clientStreamer{
   104→		cmd:    cmd,
   105→		stream: stream,
   106→		ctx:    ctx,
   107→		quitCh: make(chan struct{}),
   108→		log:    log,
   109→	}
   110→}
   111→
   112→func (s *clientStreamer) start() (workspaceapi.Pid, error) {
   113→	req := &CommandMessage{
   114→		Type: CommandMessage_TYPE_START,
   115→		Start: &StartRequest{
   116→			Path:      s.cmd.Path,
   117→			Args:      s.cmd.Args,
   118→			Dir:       s.cmd.Dir,
   119→			Env:       s.cmd.Env,
   120→			HasStdin:  s.cmd.Stdin != nil,
   121→			HasStdout: s.cmd.Stdout != nil,
   122→			HasStderr: s.cmd.Stderr != nil,
   123→		},
   124→	}
   125→
   126→	if err := s.stream.Send(req); err != nil {
   127→		return 0, fmt.Errorf("send start request: %w", err)
   128→	}
   129→
   130→	msg, err := s.stream.Recv()
   131→	if err != nil {
   132→		return 0, fmt.Errorf("recv started response: %w", err)
   133→	}
   134→
   135→	if msg.GetType() != CommandMessage_TYPE_STARTED || msg.GetStarted() == nil {
   136→		return 0, fmt.Errorf("expected started response, got %v", msg.GetType())
   137→	}
   138→
   139→	pid := workspaceapi.Pid(msg.GetStarted().GetPid())
   140→
   141→	// Start streaming I/O in background goroutines
   142→	go s.streamIO()
   143→
   144→	return pid, nil
   145→}
   146→
   147→func (s *clientStreamer) streamIO() {
   148→	defer close(s.quitCh)
   149→
   150→	// Stream stdin in background if available
   151→	if s.cmd.Stdin != nil {
   152→		go s.streamStdin()
   153→	}
   154→
   155→	// Receive stdout/stderr
   156→	s.receiveOutput()
   157→}
   158→
   159→func (s *clientStreamer) streamStdin() {
   160→	defer func() {
   161→		_ = s.stream.CloseSend()
   162→	}()
   163→
   164→	buf := make([]byte, 64*1024)
   165→	for {
   166→		select {
   167→		case <-s.quitCh:
   168→			return
   169→		case <-s.ctx.Done():
   170→			return
   171→		default:
   172→		}
   173→
   174→		n, err := s.cmd.Stdin.Read(buf)
   175→		if err != nil && err != io.EOF {
   176→			s.log.Error("read stdin", "error", err)
   177→			return
   178→		}
   179→
   180→		if n > 0 {
   181→			msg := &CommandMessage{
   182→				Type: CommandMessage_TYPE_IO,
   183→				Io: &IOData{
   184→					Type: IOData_IO_STDIN,
   185→					Data: buf[:n],
   186→				},
   187→			}
   188→			if serr := s.stream.Send(msg); serr != nil {
   189→				s.log.Error("send stdin", "error", serr)
   190→				return
   191→			}
   192→		}
   193→
   194→		if err == io.EOF {
   195→			return
   196→		}
   197→	}
   198→}
   199→
   200→func (s *clientStreamer) receiveOutput() {
   201→	var finalErr error
   202→
   203→	for {
   204→		msg, err := s.stream.Recv()
   205→		if err != nil {
   206→			if err != io.EOF {
   207→				s.log.Error("recv message", "error", err)
   208→				finalErr = err
   209→			}
   210→			break
   211→		}
   212→
   213→		switch msg.GetType() {
   214→		case CommandMessage_TYPE_IO:
   215→			io := msg.GetIo()
   216→			if io == nil {
   217→				continue
   218→			}
   219→			switch io.GetType() {
   220→			case IOData_IO_STDOUT:
   221→				if s.cmd.Stdout != nil {
   222→					_, _ = s.cmd.Stdout.Write(io.GetData())
   223→				}
   224→			case IOData_IO_STDERR:
   225→				if s.cmd.Stderr != nil {
   226→					_, _ = s.cmd.Stderr.Write(io.GetData())
   227→				}
   228→			}
   229→
   230→		case CommandMessage_TYPE_DONE:
   231→			done := msg.GetDone()
   232→			if done != nil && done.GetExitError() != "" {
   233→				finalErr = fmt.Errorf("process exit: %s", done.GetExitError())
   234→			}
   235→
   236→		case CommandMessage_TYPE_ERROR:
   237→			finalErr = fmt.Errorf("agent error: %s", msg.GetError())
   238→		}
   239→	}
   240→
   241→	// Notify watcher if present
   242→	if s.cmd.Watcher != nil && s.cmd.Watcher.WatchProcess() != nil {
   243→		select {
   244→		case s.cmd.Watcher.WatchProcess() <- finalErr:
   245→		case <-time.After(2 * time.Minute):
   246→			s.log.Warn("watcher not ready, dropping error")
   247→		}
   248→	}
   249→
   250→	// Close stdout/stderr if they implement io.Closer
   251→	if closer, ok := s.cmd.Stdout.(io.Closer); ok {
   252→		_ = closer.Close()
   253→	}
   254→	if closer, ok := s.cmd.Stderr.(io.Closer); ok {
   255→		_ = closer.Close()
   256→	}
   257→}
