    47→// StartCommand handles bidirectional streaming for command execution.
    48→func (s *Server) StartCommand(stream Agent_StartCommandServer) error {
    49→	// Receive start request
    50→	msg, err := stream.Recv()
    51→	if err != nil {
    52→		return fmt.Errorf("recv start request: %w", err)
    53→	}
    54→
    55→	if msg.GetType() != CommandMessage_TYPE_START || msg.GetStart() == nil {
    56→		return fmt.Errorf("expected start request, got %v", msg.GetType())
    57→	}
    58→
    59→	req := msg.GetStart()
    60→	s.log.Debug("starting command", "path", req.GetPath(), "args", req.GetArgs())
    61→
    62→	// Create the command
    63→	cmd := exec.Command(req.GetPath(), req.GetArgs()...)
    64→	cmd.Dir = req.GetDir()
    65→	cmd.Env = req.GetEnv()
    66→	if len(cmd.Env) == 0 {
    67→		cmd.Env = os.Environ()
    68→	}
    69→
    70→	// Set up pipes
    71→	var stdin io.WriteCloser
    72→	var stdout, stderr io.ReadCloser
    73→
    74→	if req.GetHasStdin() {
    75→		stdin, err = cmd.StdinPipe()
    76→		if err != nil {
    77→			return fmt.Errorf("stdin pipe: %w", err)
    78→		}
    79→	}
    80→
    81→	if req.GetHasStdout() {
    82→		stdout, err = cmd.StdoutPipe()
    83→		if err != nil {
    84→			return fmt.Errorf("stdout pipe: %w", err)
    85→		}
    86→	}
    87→
    88→	if req.GetHasStderr() {
    89→		stderr, err = cmd.StderrPipe()
    90→		if err != nil {
    91→			return fmt.Errorf("stderr pipe: %w", err)
    92→		}
    93→	}
    94→
    95→	// Start the command
    96→	if err := cmd.Start(); err != nil {
    97→		return fmt.Errorf("start command: %w", err)
    98→	}
    99→
   100→	pid := int64(cmd.Process.Pid)
   101→	s.processes.Store(pid, cmd.Process)
   102→	defer s.processes.Delete(pid)
   103→
   104→	// Send started response
   105→	err = stream.Send(&CommandMessage{
   106→		Type:    CommandMessage_TYPE_STARTED,
   107→		Started: &StartedResponse{Pid: pid},
   108→	})
   109→	if err != nil {
   110→		_ = cmd.Process.Kill()
   111→		return fmt.Errorf("send started: %w", err)
   112→	}
   113→
   114→	s.log.Debug("command started", "pid", pid)
   115→
   116→	// Stream I/O
   117→	var wg sync.WaitGroup
   118→	errCh := make(chan error, 3)
   119→
   120→	// Stream stdin from client to process
   121→	if stdin != nil {
   122→		wg.Add(1)
   123→		go func() {
   124→			defer wg.Done()
   125→			defer func() { _ = stdin.Close() }()
   126→			if err := s.streamStdin(stream, stdin); err != nil {
   127→				errCh <- err
   128→			}
   129→		}()
   130→	}
   131→
   132→	// Stream stdout from process to client
   133→	if stdout != nil {
   134→		wg.Add(1)
   135→		go func() {
   136→			defer wg.Done()
   137→			if err := s.streamOutput(stream, stdout, IOData_IO_STDOUT); err != nil {
   138→				errCh <- err
   139→			}
   140→		}()
   141→	}
   142→
   143→	// Stream stderr from process to client
   144→	if stderr != nil {
   145→		wg.Add(1)
   146→		go func() {
   147→			defer wg.Done()
   148→			if err := s.streamOutput(stream, stderr, IOData_IO_STDERR); err != nil {
   149→				errCh <- err
   150→			}
   151→		}()
   152→	}
   153→
   154→	// Wait for I/O to complete
   155→	wg.Wait()
   156→	close(errCh)
   157→
   158→	// Wait for the command to finish
   159→	waitErr := cmd.Wait()
   160→
   161→	// Send done response
   162→	done := &DoneResponse{}
   163→	if waitErr != nil {
   164→		done.ExitError = waitErr.Error()
   165→		var exitErr *exec.ExitError
   166→		if errors.As(waitErr, &exitErr) {
   167→			done.ExitCode = int32(exitErr.ExitCode())
   168→		}
   169→	}
   170→
   171→	err = stream.Send(&CommandMessage{
   172→		Type: CommandMessage_TYPE_DONE,
   173→		Done: done,
   174→	})
   175→	if err != nil {
   176→		return fmt.Errorf("send done: %w", err)
   177→	}
   178→
   179→	s.log.Debug("command completed", "pid", pid, "error", waitErr)
   180→	return nil
   181→}
   182→
   183→func (s *Server) streamStdin(stream Agent_StartCommandServer, stdin io.WriteCloser) error {
   184→	for {
   185→		msg, err := stream.Recv()
   186→		if err != nil {
   187→			if err == io.EOF {
   188→				return nil
   189→			}
   190→			return err
   191→		}
   192→
   193→		if msg.GetType() != CommandMessage_TYPE_IO {
   194→			continue
   195→		}
   196→
   197→		io := msg.GetIo()
   198→		if io == nil || io.GetType() != IOData_IO_STDIN {
   199→			continue
   200→		}
   201→
   202→		_, err = stdin.Write(io.GetData())
   203→		if err != nil {
   204→			return err
   205→		}
   206→	}
   207→}
   208→
   209→func (s *Server) streamOutput(
   210→	stream Agent_StartCommandServer,
   211→	r io.Reader,
   212→	ioType IOData_IOType,
   213→) error {
   214→	buf := make([]byte, 64*1024)
   215→	for {
   216→		n, err := r.Read(buf)
   217→		if err != nil {
   218→			if err == io.EOF {
   219→				return nil
   220→			}
   221→			return err
   222→		}
   223→
   224→		if n > 0 {
   225→			msg := &CommandMessage{
   226→				Type: CommandMessage_TYPE_IO,
   227→				Io: &IOData{
   228→					Type: ioType,
   229→					Data: buf[:n],
   230→				},
   231→			}
   232→			if err := stream.Send(msg); err != nil {
   233→				return err
   234→			}
   235→		}
   236→	}
   237→}
   238→
   239→// Signal sends a signal to a running process.
   240→func (s *Server) Signal(
   241→	_ context.Context, req *SignalRequest,
   242→) (*SignalResponse, error) {
   243→	v, ok := s.processes.Load(req.GetPid())
   244→	if !ok {
   245→		return nil, fmt.Errorf("process %d not found", req.GetPid())
   246→	}
   247→
   248→	proc := v.(*os.Process)
   249→	sig := syscall.Signal(req.GetSignal())
   250→
   251→	if err := proc.Signal(sig); err != nil {
   252→		return nil, fmt.Errorf("signal process: %w", err)
   253→	}
   254→
   255→	return &SignalResponse{}, nil
   256→}
   257→
   258→// Ping checks if the agent is alive.
   259→func (s *Server) Ping(_ context.Context, _ *PingRequest) (*PingResponse, error) {
   260→	return &PingResponse{Version: Version}, nil
   261→}
