// VMState represents the state of a virtual machine.
type VMState int

const (
	// VMStateUnknown indicates the VM state is unknown.
	VMStateUnknown VMState = iota
	// VMStateStarting indicates the VM is starting.
	VMStateStarting
	// VMStateRunning indicates the VM is running.
	VMStateRunning
	// VMStateStopping indicates the VM is stopping.
	VMStateStopping
	// VMStateStopped indicates the VM has stopped.
	VMStateStopped
)

// String returns a string representation of the VM state.
func (s VMState) String() string {
	switch s {
	case VMStateStarting:
		return "starting"
	case VMStateRunning:
		return "running"
	case VMStateStopping:
		return "stopping"
	case VMStateStopped:
		return "stopped"
	default:
		return "unknown"
	}
}

// Runtime is the interface for creating and managing sandbox VMs.
type Runtime interface {
	// Create creates a new VM with the given configuration.
	// The VM is started and ready to accept connections.
	Create(ctx context.Context, config *Config) (VM, error)
}

// VM represents a running sandbox virtual machine.
type VM interface {
	// ID returns a unique identifier for this VM.
	ID() string

	// State returns the current state of the VM.
	State() VMState

	// AgentConn returns a connection to the guest agent.
	// The connection can be used to communicate with the agent
	// running inside the VM via gRPC.
	// Returns an error if the VM uses a different execution mechanism.
	AgentConn() (net.Conn, error)

	// Close stops and destroys the VM.
	io.Closer
}

// ExecResult contains the result of executing a command in a VM.
type ExecResult struct {
	ExitCode int
	Stdout   []byte
	Stderr   []byte
}

// ExecOptions contains options for executing a command in a VM.
type ExecOptions struct {
	WorkingDir string
	Env        map[string]string
	User       string
	Stdin      io.Reader
	Stdout     io.Writer
	Stderr     io.Writer
}

// ExecutableVM is an optional interface for VMs that support direct command
// execution without going through an agent connection.
type ExecutableVM interface {
	VM
	// Exec executes a command in the VM and returns the result.
	Exec(ctx context.Context, command string, opts *ExecOptions) (*ExecResult, error)
	// WriteFile writes a file to the VM's filesystem.
	WriteFile(ctx context.Context, path string, content []byte, mode uint32) error
	// ReadFile reads a file from the VM's filesystem.
	ReadFile(ctx context.Context, path string) ([]byte, error)
}

