package sandbox

import (
	"context"
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"runtime"
)

const (
	// matchlockVersion is the version of Matchlock guest binaries to download.
	// This should match the version in go.mod.
	matchlockVersion = "v0.1.11"

	// githubReleaseURL is the base URL for Matchlock GitHub releases.
	githubReleaseURL = "https://github.com/jingkaihe/matchlock/releases/download"
)

// guestBinaryManager handles downloading and caching guest binaries.
type guestBinaryManager struct {
	cacheDir string
	version  string
}

// newGuestBinaryManager creates a new guest binary manager.
func newGuestBinaryManager() *guestBinaryManager {
	home, _ := os.UserHomeDir()
	return &guestBinaryManager{
		cacheDir: filepath.Join(home, ".cache", "matchlock"),
		version:  matchlockVersion,
	}
}

// guestArch returns the architecture suffix for guest binaries.
// Guest binaries are always Linux binaries (they run inside the VM).
func guestArch() string {
	// On macOS arm64, the VM runs Linux arm64
	// On macOS x86_64, the VM runs Linux x86_64 (but we don't support this)
	// On Linux, match the host architecture
	if runtime.GOARCH == "arm64" {
		return "linux-arm64"
	}
	return "linux-amd64"
}

// EnsureGuestBinaries downloads guest-agent and guest-fused if not present.
// Returns the paths to the binaries.
func (m *guestBinaryManager) EnsureGuestBinaries(ctx context.Context) (agentPath, fusedPath string, err error) {
	arch := guestArch()

	agentPath = filepath.Join(m.cacheDir, "guest-agent")
	fusedPath = filepath.Join(m.cacheDir, "guest-fused")

	// Check if binaries already exist and are valid
	if m.isValidBinary(agentPath, arch) && m.isValidBinary(fusedPath, arch) {
		return agentPath, fusedPath, nil
	}

	// Create cache directory
	if err := os.MkdirAll(m.cacheDir, 0755); err != nil {
		return "", "", fmt.Errorf("create cache dir: %w", err)
	}

	// Download guest-agent
	agentURL := fmt.Sprintf("%s/%s/guest-agent-%s", githubReleaseURL, m.version, arch)
	if err := m.downloadBinary(ctx, agentURL, agentPath); err != nil {
		return "", "", fmt.Errorf("download guest-agent: %w", err)
	}

	// Download guest-fused
	fusedURL := fmt.Sprintf("%s/%s/guest-fused-%s", githubReleaseURL, m.version, arch)
	if err := m.downloadBinary(ctx, fusedURL, fusedPath); err != nil {
		return "", "", fmt.Errorf("download guest-fused: %w", err)
	}

	return agentPath, fusedPath, nil
}

// isValidBinary checks if a binary exists and has the expected architecture.
func (m *guestBinaryManager) isValidBinary(path, expectedArch string) bool {
	fi, err := os.Stat(path)
	if err != nil || fi.Size() == 0 {
		return false
	}

	// Check ELF header for architecture
	f, err := os.Open(path)
	if err != nil {
		return false
	}
	defer f.Close()

	// Read ELF magic
	magic := make([]byte, 4)
	if _, err := f.Read(magic); err != nil {
		return false
	}
	if magic[0] != 0x7f || magic[1] != 'E' || magic[2] != 'L' || magic[3] != 'F' {
		return false
	}

	// Read e_machine at offset 18
	if _, err := f.Seek(18, 0); err != nil {
		return false
	}
	machineBytes := make([]byte, 2)
	if _, err := f.Read(machineBytes); err != nil {
		return false
	}
	machine := uint16(machineBytes[0]) | uint16(machineBytes[1])<<8

	// EM_AARCH64=183, EM_X86_64=62
	switch expectedArch {
	case "linux-arm64":
		return machine == 183
	case "linux-amd64":
		return machine == 62
	}
	return true
}

// downloadBinary downloads a file from URL to destPath.
func (m *guestBinaryManager) downloadBinary(ctx context.Context, url, destPath string) error {
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return fmt.Errorf("create request: %w", err)
	}

	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return fmt.Errorf("download: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("download failed: HTTP %d", resp.StatusCode)
	}

	// Write to temp file first
	tmpPath := destPath + ".tmp"
	f, err := os.OpenFile(tmpPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0755)
	if err != nil {
		return fmt.Errorf("create temp file: %w", err)
	}

	_, err = io.Copy(f, resp.Body)
	if closeErr := f.Close(); closeErr != nil && err == nil {
		err = closeErr
	}
	if err != nil {
		os.Remove(tmpPath)
		return fmt.Errorf("write file: %w", err)
	}

	// Atomic rename
	if err := os.Rename(tmpPath, destPath); err != nil {
		os.Remove(tmpPath)
		return fmt.Errorf("rename: %w", err)
	}

	return nil
}

// ensureGuestBinaries is a convenience function to ensure guest binaries are downloaded.
func ensureGuestBinaries(ctx context.Context) error {
	mgr := newGuestBinaryManager()
	_, _, err := mgr.EnsureGuestBinaries(ctx)
	return err
}

