   148→// monitorVsockCancel monitors the vsock fd for EOF (host closed the connection
   149→// due to cancellation) and gracefully terminates the child process using
   150→// process-group kill: SIGTERM → cancelGracePeriod → SIGKILL.
   151→//
   152→// Returns a channel that the caller MUST close after cmd.Wait() returns to
   153→// prevent signals being sent to a recycled PID.
   154→func monitorVsockCancel(fd int, cmd *exec.Cmd) chan struct{} {
   155→	waitDone := make(chan struct{})
   156→	go func() {
   157→		buf := make([]byte, 1)
   158→		syscall.Read(fd, buf)
   159→		select {
   160→		case <-waitDone:
   161→			return
   162→		default:
   163→		}
   164→		pid := cmd.Process.Pid
   165→		syscall.Kill(-pid, syscall.SIGTERM)
   166→		timer := time.AfterFunc(cancelGracePeriod, func() {
   167→			select {
   168→			case <-waitDone:
   169→				return
   170→			default:
   171→			}
   172→			syscall.Kill(-pid, syscall.SIGKILL)
   173→		})
   174→		go func() {
   175→			<-waitDone
   176→			timer.Stop()
   177→		}()
   178→	}()
   179→	return waitDone
   180→}
