   182→func handleExec(fd int) {
   183→	// Read message header (type + length)
   184→	header := make([]byte, 5)
   185→	if _, err := readFull(fd, header); err != nil {
   186→		syscall.Close(fd)
   187→		return
   188→	}
   189→
   190→	msgType := header[0]
   191→	length := uint32(header[1])<<24 | uint32(header[2])<<16 | uint32(header[3])<<8 | uint32(header[4])
   192→
   193→	// Read request data
   194→	data := make([]byte, length)
   195→	if _, err := readFull(fd, data); err != nil {
   196→		syscall.Close(fd)
   197→		return
   198→	}
   199→
   200→	switch msgType {
   201→	case MsgTypeExec:
   202→		handleExecBatch(fd, data)
   203→		syscall.Close(fd)
   204→	case MsgTypeExecStream:
   205→		handleExecStreamBatch(fd, data)
   206→		syscall.Close(fd)
   207→	case MsgTypeExecTTY:
   208→		handleExecTTY(fd, data)
   209→	default:
   210→		syscall.Close(fd)
   211→	}
   212→}
