   214→func handleExecBatch(fd int, data []byte) {
   215→	var req ExecRequest
   216→	if err := json.Unmarshal(data, &req); err != nil {
   217→		sendExecResponse(fd, &ExecResponse{Error: err.Error()})
   218→		return
   219→	}
   220→
   221→	wipeBytes(data)
   222→
   223→	var stdout, stderr bytes.Buffer
   224→	cmd := exec.Command("sh", "-c", req.Command)
   225→	cmd.Stdout = &stdout
   226→	cmd.Stderr = &stderr
   227→
   228→	if req.WorkingDir != "" {
   229→		cmd.Dir = req.WorkingDir
   230→	}
   231→
   232→	if len(req.Env) > 0 {
   233→		env := os.Environ()
   234→		for k, v := range req.Env {
   235→			env = append(env, fmt.Sprintf("%s=%s", k, v))
   236→		}
   237→		cmd.Env = env
   238→	}
   239→
   240→	applyUserEnv(cmd, req.User)
   241→	applySandboxSysProcAttrBatch(cmd)
   242→	wrapCommandForSandbox(cmd)
   243→	wipeMap(req.Env)
   244→
   245→	if err := cmd.Start(); err != nil {
   246→		sendExecResponse(fd, &ExecResponse{ExitCode: 1, Error: err.Error()})
   247→		return
   248→	}
   249→
   250→	waitDone := monitorVsockCancel(fd, cmd)
   251→
   252→	err := cmd.Wait()
   253→	close(waitDone)
   254→
   255→	resp := &ExecResponse{
   256→		Stdout: stdout.Bytes(),
   257→		Stderr: stderr.Bytes(),
   258→	}
   259→
   260→	if err != nil {
   261→		if exitErr, ok := err.(*exec.ExitError); ok {
   262→			resp.ExitCode = exitErr.ExitCode()
   263→		} else {
   264→			resp.Error = err.Error()
   265→			resp.ExitCode = 1
   266→		}
   267→	}
   268→
   269→	sendExecResponse(fd, resp)
   270→}
