   272→// handleExecStreamBatch streams stdout/stderr as MsgTypeStdout/MsgTypeStderr
   273→// chunks in real-time, then sends MsgTypeExecResult with just the exit code.
   274→func handleExecStreamBatch(fd int, data []byte) {
   275→	var req ExecRequest
   276→	if err := json.Unmarshal(data, &req); err != nil {
   277→		sendExecResponse(fd, &ExecResponse{Error: err.Error()})
   278→		return
   279→	}
   280→
   281→	wipeBytes(data)
   282→
   283→	cmd := exec.Command("sh", "-c", req.Command)
   284→
   285→	stdoutPipe, err := cmd.StdoutPipe()
   286→	if err != nil {
   287→		sendExecResponse(fd, &ExecResponse{Error: err.Error()})
   288→		return
   289→	}
   290→	stderrPipe, err := cmd.StderrPipe()
   291→	if err != nil {
   292→		sendExecResponse(fd, &ExecResponse{Error: err.Error()})
   293→		return
   294→	}
   295→
   296→	if req.WorkingDir != "" {
   297→		cmd.Dir = req.WorkingDir
   298→	}
   299→
   300→	if len(req.Env) > 0 {
   301→		env := os.Environ()
   302→		for k, v := range req.Env {
   303→			env = append(env, fmt.Sprintf("%s=%s", k, v))
   304→		}
   305→		cmd.Env = env
   306→	}
   307→
   308→	applyUserEnv(cmd, req.User)
   309→
   310→	applySandboxSysProcAttrBatch(cmd)
   311→	wrapCommandForSandbox(cmd)
   312→	wipeMap(req.Env)
   313→
   314→	if err := cmd.Start(); err != nil {
   315→		sendExecResponse(fd, &ExecResponse{ExitCode: 1, Error: err.Error()})
   316→		return
   317→	}
   318→
   319→	waitDone := monitorVsockCancel(fd, cmd)
   320→
   321→	var wg sync.WaitGroup
   322→	wg.Add(2)
   323→
   324→	go func() {
   325→		defer wg.Done()
   326→		buf := make([]byte, 4096)
   327→		for {
   328→			n, err := stdoutPipe.Read(buf)
   329→			if n > 0 {
   330→				sendMessage(fd, MsgTypeStdout, buf[:n])
   331→			}
   332→			if err != nil {
   333→				return
   334→			}
   335→		}
   336→	}()
   337→
   338→	go func() {
   339→		defer wg.Done()
   340→		buf := make([]byte, 4096)
   341→		for {
   342→			n, err := stderrPipe.Read(buf)
   343→			if n > 0 {
   344→				sendMessage(fd, MsgTypeStderr, buf[:n])
   345→			}
   346→			if err != nil {
   347→				return
   348→			}
   349→		}
   350→	}()
   351→
   352→	wg.Wait()
   353→	cmdErr := cmd.Wait()
   354→	close(waitDone)
   355→
   356→	resp := &ExecResponse{}
   357→	if cmdErr != nil {
   358→		if exitErr, ok := cmdErr.(*exec.ExitError); ok {
   359→			resp.ExitCode = exitErr.ExitCode()
   360→		} else {
   361→			resp.Error = cmdErr.Error()
   362→			resp.ExitCode = 1
   363→		}
   364→	}
   365→
   366→	sendExecResponse(fd, resp)
   367→}
