   369→func handleExecTTY(fd int, data []byte) {
   370→	var req ExecTTYRequest
   371→	if err := json.Unmarshal(data, &req); err != nil {
   372→		sendExitCode(fd, 1)
   373→		syscall.Close(fd)
   374→		return
   375→	}
   376→
   377→	// Wipe the raw request data from memory
   378→	wipeBytes(data)
   379→
   380→	cmd := exec.Command("sh", "-c", req.Command)
   381→
   382→	if req.WorkingDir != "" {
   383→		cmd.Dir = req.WorkingDir
   384→	}
   385→
   386→	if len(req.Env) > 0 {
   387→		env := os.Environ()
   388→		for k, v := range req.Env {
   389→			env = append(env, fmt.Sprintf("%s=%s", k, v))
   390→		}
   391→		cmd.Env = env
   392→	}
   393→
   394→	applyUserEnv(cmd, req.User)
   395→
   396→	// Apply sandbox isolation: PID namespace + seccomp + cap drop via re-exec
   397→	applySandboxSysProcAttr(cmd)
   398→	wrapCommandForSandbox(cmd)
   399→
   400→	// Wipe the request's env map from memory before running
   401→	wipeMap(req.Env)
   402→
   403→	// Start command with PTY
   404→	ptmx, err := pty.Start(cmd)
   405→	if err != nil {
   406→		sendExitCode(fd, 1)
   407→		syscall.Close(fd)
   408→		return
   409→	}
   410→	defer ptmx.Close()
   411→
   412→	// Set initial window size
   413→	if req.Rows > 0 && req.Cols > 0 {
   414→		pty.Setsize(ptmx, &pty.Winsize{Rows: req.Rows, Cols: req.Cols})
   415→	}
   416→
   417→	// Handle SIGCHLD to know when process exits
   418→	sigCh := make(chan os.Signal, 1)
   419→	signal.Notify(sigCh, syscall.SIGCHLD)
   420→	defer signal.Stop(sigCh)
   421→
   422→	done := make(chan struct{})
   423→
   424→	// Copy PTY output to vsock (stdout)
   425→	go func() {
   426→		buf := make([]byte, 4096)
   427→		for {
   428→			n, err := ptmx.Read(buf)
   429→			if n > 0 {
   430→				sendMessage(fd, MsgTypeStdout, buf[:n])
   431→			}
   432→			if err != nil {
   433→				break
   434→			}
   435→		}
   436→	}()
   437→
   438→	// Read messages from vsock (stdin, resize, signal)
   439→	go func() {
   440→		for {
   441→			msgType, msgData, err := readMessage(fd)
   442→			if err != nil {
   443→				break
   444→			}
   445→
   446→			switch msgType {
   447→			case MsgTypeStdin:
   448→				ptmx.Write(msgData)
   449→			case MsgTypeResize:
   450→				if len(msgData) >= 4 {
   451→					rows := binary.BigEndian.Uint16(msgData[0:2])
   452→					cols := binary.BigEndian.Uint16(msgData[2:4])
   453→					pty.Setsize(ptmx, &pty.Winsize{Rows: rows, Cols: cols})
   454→				}
   455→			case MsgTypeSignal:
   456→				if len(msgData) >= 1 {
   457→					sig := syscall.Signal(msgData[0])
   458→					cmd.Process.Signal(sig)
   459→				}
   460→			}
   461→		}
   462→	}()
   463→
   464→	// Wait for process to exit
   465→	go func() {
   466→		cmd.Wait()
   467→		close(done)
   468→	}()
   469→
   470→	<-done
   471→
   472→	exitCode := 0
   473→	if cmd.ProcessState != nil {
   474→		exitCode = cmd.ProcessState.ExitCode()
   475→	}
   476→	sendExitCode(fd, exitCode)
   477→
   478→	// Small delay to ensure exit code is transmitted before closing
   479→	time.Sleep(100 * time.Millisecond)
   480→	syscall.Close(fd)
   481→}
