   483→func applyUserEnv(cmd *exec.Cmd, user string) {
   484→	if user == "" {
   485→		return
   486→	}
   487→	if cmd.Env == nil {
   488→		cmd.Env = os.Environ()
   489→	}
   490→	cmd.Env = append(cmd.Env, "MATCHLOCK_USER="+user)
