   493→func sendMessage(fd int, msgType uint8, data []byte) {
   494→	header := make([]byte, 5)
   495→	header[0] = msgType
   496→	binary.BigEndian.PutUint32(header[1:], uint32(len(data)))
   497→	syscall.Write(fd, header)
   498→	if len(data) > 0 {
   499→		syscall.Write(fd, data)
   500→	}
   501→}
   502→
   503→func sendExitCode(fd int, code int) {
   504→	data := make([]byte, 4)
   505→	binary.BigEndian.PutUint32(data, uint32(code))
   506→	sendMessage(fd, MsgTypeExit, data)
   507→}
   508→
   509→func readMessage(fd int) (uint8, []byte, error) {
   510→	header := make([]byte, 5)
   511→	if _, err := readFull(fd, header); err != nil {
   512→		return 0, nil, err
   513→	}
   514→
   515→	msgType := header[0]
   516→	length := binary.BigEndian.Uint32(header[1:])
   517→
   518→	if length == 0 {
   519→		return msgType, nil, nil
   520→	}
   521→
   522→	data := make([]byte, length)
   523→	if _, err := readFull(fd, data); err != nil {
   524→		return 0, nil, err
   525→	}
   526→
   527→	return msgType, data, nil
   528→}
