   530→func sendExecResponse(fd int, resp *ExecResponse) {
   531→	data, err := json.Marshal(resp)
   532→	if err != nil {
   533→		return
   534→	}
   535→
   536→	header := make([]byte, 5)
   537→	header[0] = MsgTypeExecResult
   538→	header[1] = byte(len(data) >> 24)
   539→	header[2] = byte(len(data) >> 16)
   540→	header[3] = byte(len(data) >> 8)
   541→	header[4] = byte(len(data))
   542→
   543→	syscall.Write(fd, header)
   544→	syscall.Write(fd, data)
   545→}
