   547→func listenVsock(port uint32) (int, error) {
   548→	fd, err := syscall.Socket(AF_VSOCK, syscall.SOCK_STREAM, 0)
   549→	if err != nil {
   550→		return -1, fmt.Errorf("socket: %w", err)
   551→	}
   552→
   553→	addr := sockaddrVM{
   554→		Family: AF_VSOCK,
   555→		CID:    0xFFFFFFFF, // VMADDR_CID_ANY
   556→		Port:   port,
   557→	}
   558→
   559→	_, _, errno := syscall.Syscall(
   560→		syscall.SYS_BIND,
   561→		uintptr(fd),
   562→		uintptr(unsafe.Pointer(&addr)),
   563→		unsafe.Sizeof(addr),
   564→	)
   565→	if errno != 0 {
   566→		syscall.Close(fd)
   567→		return -1, fmt.Errorf("bind: %w", errno)
   568→	}
   569→
   570→	if err := syscall.Listen(fd, syscall.SOMAXCONN); err != nil {
   571→		syscall.Close(fd)
   572→		return -1, fmt.Errorf("listen: %w", err)
   573→	}
   574→
   575→	return fd, nil
   576→}
