   578→func acceptVsock(listenFd int) (int, error) {
   579→	var addr sockaddrVM
   580→	addrLen := uint32(unsafe.Sizeof(addr))
   581→
   582→	nfd, _, errno := syscall.Syscall(
   583→		syscall.SYS_ACCEPT,
   584→		uintptr(listenFd),
   585→		uintptr(unsafe.Pointer(&addr)),
   586→		uintptr(unsafe.Pointer(&addrLen)),
   587→	)
   588→	if errno != 0 {
   589→		return -1, errno
   590→	}
   591→
   592→	return int(nfd), nil
   593→}
