   595→func dialVsock(cid, port uint32) (int, error) {
   596→	fd, err := syscall.Socket(AF_VSOCK, syscall.SOCK_STREAM, 0)
   597→	if err != nil {
   598→		return -1, fmt.Errorf("socket: %w", err)
   599→	}
   600→
   601→	addr := sockaddrVM{
   602→		Family: AF_VSOCK,
   603→		CID:    cid,
   604→		Port:   port,
   605→	}
   606→
   607→	_, _, errno := syscall.Syscall(
   608→		syscall.SYS_CONNECT,
   609→		uintptr(fd),
   610→		uintptr(unsafe.Pointer(&addr)),
   611→		unsafe.Sizeof(addr),
   612→	)
   613→	if errno != 0 {
   614→		syscall.Close(fd)
   615→		return -1, fmt.Errorf("connect: %w", errno)
   616→	}
   617→
   618→	return fd, nil
   619→}
