   621→func readFull(fd int, buf []byte) (int, error) {
   622→	total := 0
   623→	for total < len(buf) {
   624→		n, err := syscall.Read(fd, buf[total:])
   625→		if err != nil {
   626→			return total, err
   627→		}
   628→		if n == 0 {
   629→			return total, fmt.Errorf("EOF")
   630→		}
   631→		total += n
   632→	}
   633→	return total, nil
   634→}
