    87→		return []uint32{
    88→			sysProcessVMReadvArm64,
    89→			sysProcessVMWritevArm64,
    90→			sysPtraceArm64,
    91→			sysKexecLoadArm64,
    92→			sysKexecFileLoadArm64,
    93→		}, auditArchAARCH64
    94→	default:
    95→		return []uint32{
    96→			sysProcessVMReadvAmd64,
    97→			sysProcessVMWritevAmd64,
    98→			sysPtraceAmd64,
    99→			sysKexecLoadAmd64,
   100→			sysKexecFileLoadAmd64,
   101→		}, auditArchX86_64
   102→	}
   103→}
