   105→// buildSeccompFilter creates a BPF program that blocks dangerous syscalls
   106→// (process_vm_readv, process_vm_writev, ptrace, kexec_load, kexec_file_load)
   107→// with EPERM. All other syscalls are allowed.
   108→func buildSeccompFilter() []sockFilter {
   109→	blocked, auditArch := blockedSyscalls()
   110→
   111→	filter := []sockFilter{
   112→		bpfStmt(bpfLD|bpfW|bpfABS, 4),
   113→		bpfJump(bpfJMP|bpfJEQ|bpfK, auditArch, 0, uint8(len(blocked)+1)),
   114→		bpfStmt(bpfLD|bpfW|bpfABS, 0),
   115→	}
   116→
   117→	for i, nr := range blocked {
   118→		remaining := uint8(len(blocked) - i - 1)
   119→		filter = append(filter, bpfJump(bpfJMP|bpfJEQ|bpfK, nr, remaining+1, 0))
   120→	}
   121→
   122→	filter = append(filter, bpfStmt(bpfRET|bpfK, seccompRetAllow))
   123→	filter = append(filter, bpfStmt(bpfRET|bpfK, seccompRetErrno|errnoEPERM))
   124→
   125→	return filter
   126→}
   127→
   128→// sandboxLauncherEnvKey is the environment variable used to signal that this
   129→// process is a re-execed sandbox launcher (not the main agent).
   130→const sandboxLauncherEnvKey = "__MATCHLOCK_SANDBOX_LAUNCHER"
   131→
   132→// isPrivilegedMode checks /proc/cmdline for matchlock.privileged=1.
   133→// When privileged, the sandbox launcher skips cap drops, seccomp, and no_new_privs.
   134→func isPrivilegedMode() bool {
   135→	data, err := os.ReadFile("/proc/cmdline")
   136→	if err != nil {
   137→		return false
   138→	}
   139→	for _, field := range strings.Fields(string(data)) {
   140→		if field == "matchlock.privileged=1" {
   141→			return true
   142→		}
   143→	}
   144→	return false
   145→}
   146→
   147→// isSandboxLauncher returns true if this process was re-execed as a sandbox launcher.
   148→func isSandboxLauncher() bool {
   149→	return os.Getenv(sandboxLauncherEnvKey) == "1"
   150→}
   151→
   152→// runSandboxLauncher is the entrypoint for the re-execed process.
   153→// It drops capabilities, installs seccomp, then execs the real command.
   154→func runSandboxLauncher() {
   155→	// Remove our marker so child doesn't inherit it
   156→	os.Unsetenv(sandboxLauncherEnvKey)
   157→
   158→	// Remount /proc for our new PID namespace so the workload only sees
   159→	// its own processes, not the guest-agent in the parent namespace.
   160→	syscall.Unmount("/proc", syscall.MNT_DETACH)
   161→	syscall.Mount("proc", "/proc", "proc", 0, "")
   162→
   163→	privileged := isPrivilegedMode()
   164→
   165→	if !privileged {
   166→		// Drop specific dangerous capabilities from the bounding set
   167→		for _, cap := range []uintptr{capSysPtrace, capSysAdmin, capSysModule, capSysRawio, capSysBoot} {
   168→			syscall.RawSyscall(syscall.SYS_PRCTL, prCapBSetDrop, cap, 0)
   169→		}
   170→
   171→		// Set no_new_privs (required for seccomp and prevents privilege escalation)
   172→		if _, _, errno := syscall.RawSyscall(syscall.SYS_PRCTL, prSetNoNewPrivs, 1, 0); errno != 0 {
   173→			fmt.Fprintf(os.Stderr, "matchlock: failed to set no_new_privs: %v\n", errno)
   174→			os.Exit(127)
   175→		}
   176→
   177→		// Install seccomp filter
   178→		filter := buildSeccompFilter()
   179→		prog := sockFprog{
   180→			Len:    uint16(len(filter)),
   181→			Filter: &filter[0],
   182→		}
   183→		if _, _, errno := syscall.RawSyscall(syscall.SYS_PRCTL, prSetSeccomp, seccompModeFilter, uintptr(unsafe.Pointer(&prog))); errno != 0 {
   184→			fmt.Fprintf(os.Stderr, "matchlock: failed to install seccomp filter: %v\n", errno)
   185→			os.Exit(127)
   186→		}
   187→	}
   188→
   189→	// The command to exec is passed via MATCHLOCK_CMD env var,
   190→	// and individual args via MATCHLOCK_ARG_0, MATCHLOCK_ARG_1, etc.
   191→	command := os.Getenv("MATCHLOCK_CMD")
   192→	os.Unsetenv("MATCHLOCK_CMD")
   193→
   194→	var args []string
   195→	for i := 0; ; i++ {
   196→		key := fmt.Sprintf("MATCHLOCK_ARG_%d", i)
   197→		val, ok := os.LookupEnv(key)
   198→		if !ok {
   199→			break
   200→		}
   201→		args = append(args, val)
   202→		os.Unsetenv(key)
   203→	}
   204→
   205→	if command == "" {
   206→		fmt.Fprintf(os.Stderr, "matchlock: no command specified\n")
   207→		os.Exit(127)
   208→	}
   209→
   210→	// Find the binary
   211→	binary, err := exec.LookPath(command)
   212→	if err != nil {
   213→		fmt.Fprintf(os.Stderr, "matchlock: %v\n", err)
   214→		os.Exit(127)
   215→	}
   216→
   217→	argv := append([]string{command}, args...)
   218→
   219→	// Switch user if requested via MATCHLOCK_USER env var
   220→	userSpec := os.Getenv("MATCHLOCK_USER")
   221→	os.Unsetenv("MATCHLOCK_USER")
   222→	if userSpec != "" {
   223→		uid, gid, homeDir, err := resolveUser(userSpec)
   224→		if err != nil {
   225→			fmt.Fprintf(os.Stderr, "matchlock: resolve user %q: %v\n", userSpec, err)
   226→			os.Exit(127)
   227→		}
   228→		if err := syscall.Setgroups([]int{gid}); err != nil {
   229→			fmt.Fprintf(os.Stderr, "matchlock: setgroups([%d]): %v\n", gid, err)
   230→			os.Exit(127)
   231→		}
   232→		if err := syscall.Setgid(gid); err != nil {
   233→			fmt.Fprintf(os.Stderr, "matchlock: setgid(%d): %v\n", gid, err)
   234→			os.Exit(127)
   235→		}
   236→		if err := syscall.Setuid(uid); err != nil {
   237→			fmt.Fprintf(os.Stderr, "matchlock: setuid(%d): %v\n", uid, err)
   238→			os.Exit(127)
   239→		}
   240→		if homeDir != "" {
   241→			os.Setenv("HOME", homeDir)
   242→		}
   243→	}
   244→
   245→	// Filter out our internal env vars from the environment
   246→	var env []string
   247→	for _, e := range os.Environ() {
   248→		if strings.HasPrefix(e, "MATCHLOCK_CMD=") || strings.HasPrefix(e, "MATCHLOCK_ARG_") || strings.HasPrefix(e, sandboxLauncherEnvKey+"=") || strings.HasPrefix(e, "MATCHLOCK_USER=") {
   249→			continue
   250→		}
   251→		env = append(env, e)
   252→	}
   253→
   254→	// Exec the real command (replaces this process)
   255→	err = syscall.Exec(binary, argv, env)
   256→	if err != nil {
   257→		fmt.Fprintf(os.Stderr, "matchlock: exec %s: %v\n", command, err)
   258→		os.Exit(127)
   259→	}
   260→}
   261→
   262→// applySandboxSysProcAttr configures the child process with:
   263→// - PID namespace isolation (CLONE_NEWPID) so workload can't see the agent
   264→// - Pdeathsig to kill child if agent dies
   265→//
   266→// The command is wrapped: instead of running `sh -c <cmd>` directly,
   267→// we re-exec the guest-agent binary with sandboxLauncherEnvKey set.
   268→// The launcher then drops caps, installs seccomp, and execs the real command.
   269→func applySandboxSysProcAttr(cmd *exec.Cmd) {
   270→	cmd.SysProcAttr = &syscall.SysProcAttr{
   271→		Cloneflags: syscall.CLONE_NEWPID | syscall.CLONE_NEWNS,
   272→		Pdeathsig:  syscall.SIGKILL,
   273→	}
   274→}
   275→
   276→// applySandboxSysProcAttrBatch is like applySandboxSysProcAttr but also sets
   277→// Setpgid so the child gets its own process group. This enables process-group
   278→// kill (-pid) for cancellation. Must NOT be used with PTY exec because
   279→// pty.Start sets Setsid which conflicts with Setpgid.
   280→func applySandboxSysProcAttrBatch(cmd *exec.Cmd) {
   281→	applySandboxSysProcAttr(cmd)
   282→	cmd.SysProcAttr.Setpgid = true
   283→}
   284→
   285→// wrapCommandForSandbox rewrites the exec.Cmd to use the re-exec launcher pattern.
   286→// The original command is passed via environment variables, and the binary is
   287→// replaced with /proc/self/exe (the guest-agent itself).
   288→func wrapCommandForSandbox(cmd *exec.Cmd) {
   289→	origArgs := cmd.Args // e.g. ["sh", "-c", "python3 script.py"]
   290→
   291→	// Set the binary to re-exec ourselves
   292→	cmd.Path = "/proc/self/exe"
   293→	cmd.Args = []string{"guest-agent"}
   294→
   295→	// Pass the original command via env vars
   296→	if cmd.Env == nil {
   297→		cmd.Env = os.Environ()
   298→	}
   299→	cmd.Env = append(cmd.Env, sandboxLauncherEnvKey+"=1")
   300→
   301→	if len(origArgs) > 0 {
   302→		cmd.Env = append(cmd.Env, "MATCHLOCK_CMD="+origArgs[0])
   303→		for i, arg := range origArgs[1:] {
   304→			cmd.Env = append(cmd.Env, fmt.Sprintf("MATCHLOCK_ARG_%d=%s", i, arg))
   305→		}
   306→	}
   307→}
