   309→// resolveUser resolves a user spec ("uid", "uid:gid", or "username") to numeric
   310→// UID, GID, and home directory by parsing /etc/passwd and /etc/group.
   311→func resolveUser(spec string) (uid, gid int, homeDir string, err error) {
   312→	return resolveUserFrom(spec, "/etc/passwd", "/etc/group")
   313→}
   314→
   315→func resolveUserFrom(spec, passwdPath, groupPath string) (uid, gid int, homeDir string, err error) {
   316→	if parts := strings.SplitN(spec, ":", 2); len(parts) == 2 {
   317→		uid, err = resolveUIDFrom(parts[0], passwdPath)
   318→		if err != nil {
   319→			return 0, 0, "", fmt.Errorf("resolve uid %q: %w", parts[0], err)
   320→		}
   321→		gid, err = resolveGIDFrom(parts[1], groupPath)
   322→		if err != nil {
   323→			return 0, 0, "", fmt.Errorf("resolve gid %q: %w", parts[1], err)
   324→		}
   325→		_, _, homeDir = lookupPasswdByUIDFrom(uid, passwdPath)
   326→		return uid, gid, homeDir, nil
   327→	}
   328→
   329→	if n, err := strconv.Atoi(spec); err == nil {
   330→		gid, _, homeDir = lookupPasswdByUIDFrom(n, passwdPath)
   331→		return n, gid, homeDir, nil
   332→	}
   333→
   334→	uid, gid, homeDir, ok := lookupPasswdByNameFrom(spec, passwdPath)
   335→	if !ok {
   336→		return 0, 0, "", fmt.Errorf("user %q not found in /etc/passwd", spec)
   337→	}
   338→	return uid, gid, homeDir, nil
   339→}
   340→
   341→func resolveUIDFrom(s, passwdPath string) (int, error) {
   342→	if n, err := strconv.Atoi(s); err == nil {
   343→		return n, nil
   344→	}
   345→	uid, _, _, ok := lookupPasswdByNameFrom(s, passwdPath)
   346→	if !ok {
   347→		return 0, fmt.Errorf("user %q not found", s)
   348→	}
   349→	return uid, nil
   350→}
   351→
   352→func resolveGIDFrom(s, groupPath string) (int, error) {
   353→	if n, err := strconv.Atoi(s); err == nil {
   354→		return n, nil
   355→	}
   356→	f, err := os.Open(groupPath)
   357→	if err != nil {
   358→		return 0, err
   359→	}
   360→	defer f.Close()
   361→	scanner := bufio.NewScanner(f)
   362→	for scanner.Scan() {
   363→		line := scanner.Text()
   364→		if strings.HasPrefix(line, "#") || line == "" {
   365→			continue
   366→		}
   367→		fields := strings.SplitN(line, ":", 4)
   368→		if len(fields) >= 3 && fields[0] == s {
   369→			gid, err := strconv.Atoi(fields[2])
   370→			if err == nil {
   371→				return gid, nil
   372→			}
   373→		}
   374→	}
   375→	return 0, fmt.Errorf("group %q not found", s)
   376→}
   377→
   378→func lookupPasswdByNameFrom(name, passwdPath string) (int, int, string, bool) {
   379→	f, err := os.Open(passwdPath)
   380→	if err != nil {
   381→		return 0, 0, "", false
   382→	}
   383→	defer f.Close()
   384→	scanner := bufio.NewScanner(f)
   385→	for scanner.Scan() {
   386→		line := scanner.Text()
   387→		if strings.HasPrefix(line, "#") || line == "" {
   388→			continue
   389→		}
   390→		fields := strings.SplitN(line, ":", 7)
   391→		if len(fields) >= 6 && fields[0] == name {
   392→			uid, _ := strconv.Atoi(fields[2])
   393→			gid, _ := strconv.Atoi(fields[3])
   394→			return uid, gid, fields[5], true
   395→		}
   396→	}
   397→	return 0, 0, "", false
   398→}
   399→
   400→func lookupPasswdByUIDFrom(uid int, passwdPath string) (gid int, shell string, homeDir string) {
   401→	f, err := os.Open(passwdPath)
   402→	if err != nil {
   403→		return uid, "", ""
   404→	}
   405→	defer f.Close()
   406→	uidStr := strconv.Itoa(uid)
   407→	scanner := bufio.NewScanner(f)
   408→	for scanner.Scan() {
   409→		line := scanner.Text()
   410→		if strings.HasPrefix(line, "#") || line == "" {
   411→			continue
   412→		}
   413→		fields := strings.SplitN(line, ":", 7)
   414→		if len(fields) >= 6 && fields[2] == uidStr {
   415→			gid, _ := strconv.Atoi(fields[3])
   416→			shell := ""
   417→			if len(fields) >= 7 {
   418→				shell = fields[6]
   419→			}
   420→			return gid, shell, fields[5]
   421→		}
   422→	}
   423→	return uid, "", ""
   424→}
