   169→// ensureRealDir ensures that every component of path under root is a real
   170→// directory, not a symlink. If an intermediate component is a symlink it is
   171→// replaced with a real directory so that later file creation won't chase
   172→// symlink chains (which can cause ELOOP on images with deep/circular symlinks).
   173→func ensureRealDir(root, path string) error {
   174→	rel, err := filepath.Rel(root, path)
   175→	if err != nil {
   176→		return err
   177→	}
   178→	parts := strings.Split(rel, string(filepath.Separator))
   179→	cur := root
   180→	for _, p := range parts {
   181→		cur = filepath.Join(cur, p)
   182→		fi, err := os.Lstat(cur)
   183→		if os.IsNotExist(err) {
   184→			if err := os.Mkdir(cur, 0755); err != nil {
   185→				return err
   186→			}
   187→			continue
   188→		}
   189→		if err != nil {
   190→			return err
   191→		}
   192→		if fi.Mode()&os.ModeSymlink != 0 {
   193→			if err := os.Remove(cur); err != nil {
   194→				return err
   195→			}
   196→			if err := os.Mkdir(cur, 0755); err != nil {
