    21→// createExt4 creates an ext4 filesystem using debugfs (no root required)
    22→func (b *Builder) createExt4(sourceDir, destPath string, meta map[string]fileMeta) error {
    23→	mke2fsPath, err := exec.LookPath("mke2fs")
    24→	if err != nil {
    25→		mke2fsPath, err = exec.LookPath("mkfs.ext4")
    26→		if err != nil {
    27→			return fmt.Errorf("mke2fs/mkfs.ext4 not found; install e2fsprogs")
    28→		}
    29→	}
    30→
    31→	debugfsPath, err := exec.LookPath("debugfs")
    32→	if err != nil {
    33→		return fmt.Errorf("debugfs not found; install e2fsprogs")
    34→	}
    35→
    36→	var totalSize int64
    37→	lstatWalk(sourceDir, func(path string, info os.FileInfo) {
    38→		totalSize += info.Size()
    39→	})
    40→
    41→	sizeMB := (totalSize / (1024 * 1024)) + 64
    42→
    43→	tmpPath := destPath + "." + uuid.New().String() + ".tmp"
    44→
    45→	cmd := exec.Command("dd", "if=/dev/zero", "of="+tmpPath, "bs=1M", fmt.Sprintf("count=%d", sizeMB), "conv=sparse")
    46→	cmd.Stderr = nil
    47→	if out, err := cmd.CombinedOutput(); err != nil {
    48→		os.Remove(tmpPath)
    49→		return fmt.Errorf("create sparse file: %w: %s", err, out)
    50→	}
    51→
    52→	cmd = exec.Command(mke2fsPath, "-t", "ext4", "-F", "-q", tmpPath)
    53→	if out, err := cmd.CombinedOutput(); err != nil {
    54→		os.Remove(tmpPath)
    55→		return fmt.Errorf("mke2fs: %w: %s", err, out)
    56→	}
    57→
    58→	var debugfsCommands strings.Builder
    59→
    60→	err = lstatWalkErr(sourceDir, func(path string, info os.FileInfo) error {
    61→		relPath, _ := filepath.Rel(sourceDir, path)
    62→		if relPath == "." {
    63→			return nil
    64→		}
    65→
    66→		ext4Path := "/" + relPath
    67→
    68→		if hasDebugfsUnsafeChars(ext4Path) {
    69→			return nil
    70→		}
    71→
    72→		if info.IsDir() {
    73→			debugfsCommands.WriteString(fmt.Sprintf("mkdir %s\n", ext4Path))
    74→		} else if info.Mode().IsRegular() {
    75→			debugfsCommands.WriteString(fmt.Sprintf("write %s %s\n", path, ext4Path))
    76→		} else if info.Mode()&os.ModeSymlink != 0 {
    77→			target, err := os.Readlink(path)
    78→			if err == nil {
    79→				debugfsCommands.WriteString(fmt.Sprintf("symlink %s %s\n", ext4Path, target))
    80→			}
    81→		}
    82→
    83→		if fm, ok := meta[ext4Path]; ok {
    84→			debugfsCommands.WriteString(fmt.Sprintf("set_inode_field %s uid %d\n", ext4Path, fm.uid))
    85→			debugfsCommands.WriteString(fmt.Sprintf("set_inode_field %s gid %d\n", ext4Path, fm.gid))
    86→			var typeBits uint32
    87→			if info.IsDir() {
    88→				typeBits = 0o040000
    89→			} else if info.Mode()&os.ModeSymlink != 0 {
    90→				typeBits = 0o120000
    91→			} else {
    92→				typeBits = 0o100000
    93→			}
    94→			debugfsCommands.WriteString(fmt.Sprintf("set_inode_field %s mode 0%o\n", ext4Path, typeBits|uint32(fm.mode)))
    95→		}
    96→		return nil
    97→	})
    98→	if err != nil {
    99→		os.Remove(tmpPath)
   100→		return fmt.Errorf("walk source dir: %w", err)
   101→	}
   102→
   103→	cmd = exec.Command(debugfsPath, "-w", "-f", "/dev/stdin", tmpPath)
   104→	cmd.Stdin = strings.NewReader(debugfsCommands.String())
   105→	if out, err := cmd.CombinedOutput(); err != nil {
   106→		os.Remove(tmpPath)
   107→		return fmt.Errorf("debugfs: %w: %s", err, out)
   108→	}
   109→
   110→	if err := os.Rename(tmpPath, destPath); err != nil {
   111→		os.Remove(tmpPath)
   112→		return fmt.Errorf("rename: %w", err)
   113→	}
   114→
   115→	return nil
   116→}
