   166→// Start starts a command in the sandbox and returns its PID.
   167→// This method implements workspaceapi.Executor.
   168→func (e *Executor) Start(
   169→	ctx context.Context, cmd workspaceapi.Cmd,
   170→) (workspaceapi.Pid, error) {
   171→	e.mu.RLock()
   172→	defer e.mu.RUnlock()
   173→
   174→	if e.closed {
   175→		return 0, ErrClosed
   176→	}
   177→
   178→	if cmd.Path == "" {
   179→		return 0, ErrInvalidCommand
   180→	}
   181→
   182→	// Scrub environment variables according to policy
   183→	cmd.Env = e.scrubEnvironment(cmd.Env)
   184→
   185→	// Use direct exec if available
   186→	if e.execVM != nil {
   187→		return e.startWithExec(ctx, cmd)
   188→	}
   189→
   190→	// Fall back to agent
   191→	return e.agent.StartCommand(ctx, cmd)
   192→}
   193→
   194→// scrubEnvironment filters environment variables according to the configured policy.
   195→func (e *Executor) scrubEnvironment(env []string) []string {
   196→	var envPolicy *policy.EnvironmentPolicy
   197→	if e.config.Policy != nil {
   198→		envPolicy = e.config.Policy.Environment
   199→	}
   200→	if envPolicy == nil {
   201→		// Use default policy if none configured
   202→		envPolicy = policy.DefaultEnvironmentPolicy()
   203→	}
   204→	return envPolicy.ScrubEnvironment(env)
   205→}
   206→
   207→// startWithExec uses the VM's direct Exec method.
   208→func (e *Executor) startWithExec(ctx context.Context, cmd workspaceapi.Cmd) (workspaceapi.Pid, error) {
   209→	// Build command string
   210→	command := cmd.Path
   211→	if len(cmd.Args) > 0 {
   212→		command = command + " " + strings.Join(cmd.Args, " ")
   213→	}
   214→
   215→	// Create exec options
   216→	opts := &ExecOptions{
   217→		WorkingDir: cmd.Dir,
   218→		Env:        make(map[string]string),
   219→	}
   220→
   221→	// Parse environment variables
   222→	for _, env := range cmd.Env {
   223→		parts := strings.SplitN(env, "=", 2)
   224→		if len(parts) == 2 {
   225→			opts.Env[parts[0]] = parts[1]
   226→		}
   227→	}
   228→
   229→	// Set up I/O
   230→	opts.Stdin = cmd.Stdin
   231→	opts.Stdout = cmd.Stdout
   232→	opts.Stderr = cmd.Stderr
   233→
   234→	// Generate PID
   235→	pid := workspaceapi.Pid(e.pidCounter.Add(1))
   236→
   237→	// Create cancellable context for this process
   238→	procCtx, cancel := context.WithCancel(ctx)
   239→	e.processes.Store(pid, cancel)
   240→
   241→	// Run command in background
   242→	go func() {
   243→		defer e.processes.Delete(pid)
   244→		defer cancel()
   245→
   246→		var stdoutBuf, stderrBuf bytes.Buffer
   247→		execOpts := &ExecOptions{
   248→			WorkingDir: opts.WorkingDir,
   249→			Env:        opts.Env,
   250→		}
   251→
   252→		// If streaming I/O is provided, pass it through
   253→		if opts.Stdout != nil {
   254→			execOpts.Stdout = opts.Stdout
   255→		} else {
   256→			execOpts.Stdout = &stdoutBuf
   257→		}
   258→		if opts.Stderr != nil {
   259→			execOpts.Stderr = opts.Stderr
   260→		} else {
   261→			execOpts.Stderr = &stderrBuf
   262→		}
   263→		if opts.Stdin != nil {
   264→			execOpts.Stdin = opts.Stdin
   265→		}
   266→
   267→		result, err := e.execVM.Exec(procCtx, command, execOpts)
   268→
   269→		// Notify watcher
   270→		if cmd.Watcher != nil && cmd.Watcher.WatchProcess() != nil {
   271→			var watchErr error
   272→			if err != nil {
   273→				watchErr = err
   274→			} else if result != nil && result.ExitCode != 0 {
   275→				watchErr = fmt.Errorf("exit status %d", result.ExitCode)
   276→			}
   277→
   278→			select {
   279→			case cmd.Watcher.WatchProcess() <- watchErr:
   280→			case <-time.After(2 * time.Minute):
   281→				e.log.Warn("watcher not ready, dropping result")
   282→			}
   283→		}
   284→
   285→		// Close output streams if they implement io.Closer
   286→		if closer, ok := cmd.Stdout.(io.Closer); ok {
   287→			_ = closer.Close()
   288→		}
   289→		if closer, ok := cmd.Stderr.(io.Closer); ok {
   290→			_ = closer.Close()
   291→		}
   292→	}()
   293→
   294→	return pid, nil
   295→}
   296→
   297→// Signal sends a signal to a process running in the sandbox.
   298→// This method implements workspaceapi.Executor.
   299→func (e *Executor) Signal(pid workspaceapi.Pid, sig syscall.Signal) error {
   300→	e.mu.RLock()
   301→	defer e.mu.RUnlock()
   302→
   303→	if e.closed {
   304→		return ErrClosed
   305→	}
   306→
   307→	if pid <= 0 {
   308→		return ErrProcessNotFound
   309→	}
   310→
   311→	// Use direct cancellation for ExecutableVM
   312→	if e.execVM != nil {
   313→		v, ok := e.processes.Load(pid)
   314→		if !ok {
   315→			return ErrProcessNotFound
   316→		}
   317→		cancel := v.(context.CancelFunc)
   318→		// For SIGTERM/SIGKILL, cancel the context
   319→		if sig == syscall.SIGTERM || sig == syscall.SIGKILL {
   320→			cancel()
   321→		}
   322→		return nil
   323→	}
   324→
   325→	// Fall back to agent
   326→	return e.agent.Signal(pid, sig)
   327→}
   328→
   329→// Close stops the sandbox and releases all resources.
   330→// This method implements io.Closer.
   331→func (e *Executor) Close() error {
   332→	e.mu.Lock()
   333→	defer e.mu.Unlock()
   334→
   335→	if e.closed {
   336→		return nil
   337→	}
   338→	e.closed = true
   339→
   340→	var errs []error
   341→
   342→	// Cancel all running processes
   343→	e.processes.Range(func(_, value any) bool {
   344→		cancel := value.(context.CancelFunc)
   345→		cancel()
   346→		return true
   347→	})
   348→
   349→	if e.agent != nil {
   350→		if err := e.agent.Close(); err != nil {
   351→			errs = append(errs, fmt.Errorf("close agent: %w", err))
   352→		}
   353→	}
   354→
   355→	if e.conn != nil {
   356→		if err := e.conn.Close(); err != nil {
   357→			errs = append(errs, fmt.Errorf("close grpc conn: %w", err))
   358→		}
   359→	}
   360→
   361→	if e.vm != nil {
   362→		if err := e.vm.Close(); err != nil {
   363→			errs = append(errs, fmt.Errorf("close vm: %w", err))
   364→		}
   365→	}
   366→
   367→	e.log.Info("sandbox executor closed", "vm_id", e.vm.ID())
   368→	return errors.Join(errs...)
   369→}
   370→
   371→// VM returns the underlying VM. This is primarily for testing.
   372→func (e *Executor) VM() VM {
   373→	return e.vm
   374→}
   375→
   376→// Config returns the executor's configuration.
   377→func (e *Executor) Config() Config {
   378→	return e.config
   379→}
