    17→    rpc Ping(PingRequest) returns (PingResponse);
    18→}
    19→
    20→// CommandMessage is the bidirectional streaming message for command I/O.
    21→message CommandMessage {
    22→    // Type indicates the message type.
    23→    Type type = 1;
    24→
    25→    // StartRequest is set when type is TYPE_START.
    26→    StartRequest start = 2;
    27→
    28→    // Started is set when type is TYPE_STARTED.
    29→    StartedResponse started = 3;
    30→
    31→    // IO is set when type is TYPE_IO.
    32→    IOData io = 4;
    33→
    34→    // Done is set when type is TYPE_DONE.
    35→    DoneResponse done = 5;
    36→
    37→    // Error is set when type is TYPE_ERROR.
    38→    string error = 6;
    39→
    40→    enum Type {
    41→        TYPE_START = 0;
    42→        TYPE_STARTED = 1;
    43→        TYPE_IO = 2;
    44→        TYPE_DONE = 3;
    45→        TYPE_ERROR = 4;
    46→    }
    47→}
    48→
    49→// StartRequest contains the command to start.
    50→message StartRequest {
    51→    // Path is the path to the executable.
    52→    string path = 1;
    53→
    54→    // Args are the command arguments (not including path).
    55→    repeated string args = 2;
    56→
    57→    // Dir is the working directory. If empty, uses the workspace root.
    58→    string dir = 3;
    59→
    60→    // Env contains environment variables in KEY=value format.
    61→    repeated string env = 4;
    62→
    63→    // HasStdin indicates whether stdin will be provided.
    64→    bool has_stdin = 5;
    65→
    66→    // HasStdout indicates whether stdout should be captured.
    67→    bool has_stdout = 6;
    68→
    69→    // HasStderr indicates whether stderr should be captured.
    70→    bool has_stderr = 7;
    71→}
    72→
    73→// StartedResponse indicates a command has started.
