### Example - Server Listener
```go
socketDevice := vm.SocketDevices()[0]

// Listen on port 5000
listener, err := socketDevice.Listen(5000)
if err != nil {
    return err
}
defer listener.Close()

// Accept connections
for {
    conn, err := listener.AcceptVirtioSocketConnection()
    if err != nil {
        return err
    }

    // Handle connection
    go handleConnection(conn)
}
```

