    47→// StartCommand handles bidirectional streaming for command execution.
    48→func (s *Server) StartCommand(stream Agent_StartCommandServer) error {
    49→	// Receive start request
    50→	msg, err := stream.Recv()
    51→	if err != nil {
    52→		return fmt.Errorf("recv start request: %w", err)
    53→	}
    54→
    55→	if msg.GetType() != CommandMessage_TYPE_START || msg.GetStart() == nil {
    56→		return fmt.Errorf("expected start request, got %v", msg.GetType())
    57→	}
    58→
    59→	req := msg.GetStart()
    60→	s.log.Debug("starting command", "path", req.GetPath(), "args", req.GetArgs())
    61→
    62→	// Create the command
    63→	cmd := exec.Command(req.GetPath(), req.GetArgs()...)
    64→	cmd.Dir = req.GetDir()
    65→	cmd.Env = req.GetEnv()
    66→	if len(cmd.Env) == 0 {
    67→		cmd.Env = os.Environ()
    68→	}
    69→
    70→	// Set up pipes
    71→	var stdin io.WriteCloser
    72→	var stdout, stderr io.ReadCloser
    73→
    74→	if req.GetHasStdin() {
    75→		stdin, err = cmd.StdinPipe()
    76→		if err != nil {
    77→			return fmt.Errorf("stdin pipe: %w", err)
    78→		}
    79→	}
    80→
    81→	if req.GetHasStdout() {
    82→		stdout, err = cmd.StdoutPipe()
    83→		if err != nil {
    84→			return fmt.Errorf("stdout pipe: %w", err)
    85→		}
    86→	}
    87→
    88→	if req.GetHasStderr() {
    89→		stderr, err = cmd.StderrPipe()
    90→		if err != nil {
    91→			return fmt.Errorf("stderr pipe: %w", err)
    92→		}
    93→	}
    94→
    95→	// Start the command
    96→	if err := cmd.Start(); err != nil {
    97→		return fmt.Errorf("start command: %w", err)
    98→	}
    99→
   100→	pid := int64(cmd.Process.Pid)
   101→	s.processes.Store(pid, cmd.Process)
   102→	defer s.processes.Delete(pid)
   103→
