   105→	err = stream.Send(&CommandMessage{
   106→		Type:    CommandMessage_TYPE_STARTED,
   107→		Started: &StartedResponse{Pid: pid},
   108→	})
   109→	if err != nil {
   110→		_ = cmd.Process.Kill()
