   125→			defer func() { _ = stdin.Close() }()
   126→			if err := s.streamStdin(stream, stdin); err != nil {
   127→				errCh <- err
   128→			}
   129→		}()
   130→	}
   131→
   132→	// Stream stdout from process to client
   133→	if stdout != nil {
