    60→
    61→	mu     sync.RWMutex
    62→	closed bool
    63→}
    64→
    65→// Option is a functional option for configuring an Executor.
    66→type Option func(*Executor)
    67→
    68→// WithRuntime sets a custom runtime for the executor.
    69→// This is primarily used for testing.
    70→func WithRuntime(r Runtime) Option {
    71→	return func(e *Executor) {
    72→		e.runtime = r
    73→	}
    74→}
    75→
    76→// WithLogger sets a custom logger for the executor.
    77→func WithLogger(log *slog.Logger) Option {
    78→	return func(e *Executor) {
    79→		e.log = log
    80→	}
    81→}
    82→
    83→// New creates a new sandbox executor. The VM is started immediately and
    84→// will be ready to accept commands upon return. The caller is responsible
    85→// for calling Close() when the executor is no longer needed.
    86→func New(ctx context.Context, config Config, opts ...Option) (*Executor, error) {
    87→	e := &Executor{
    88→		config: config,
    89→		log:    slog.Default().With("struct", "sandbox.Executor"),
    90→	}
    91→
    92→	for _, opt := range opts {
    93→		opt(e)
